  1→import React, {useCallback, useMemo, useRef, useState} from 'react';
  2→import {
  3→  ActivityIndicator,
  4→  Alert,
  5→  Image,
  6→  Pressable,
  7→  ScrollView,
  8→  StyleSheet,
  9→  Text,
 10→  TextInput,
 11→  View,
 12→} from 'react-native';
 13→import {useMutation, useQuery} from '@tanstack/react-query';
 14→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 15→import {SafeAreaView} from 'react-native-safe-area-context';
 16→import {Avatar} from '../../components/Avatar';
 17→import {BadgeCheckIcon, XIcon} from '../../components/icons';
 18→import {CommentThread, formatRelativeDate} from '../../components/Comments';
 19→import {ActionBar} from '../../components/PostCard/ActionBar';
 20→import {PrimaryButton} from '../../components/PrimaryButton';
 21→import {SkeletonLoader} from '../../components/SkeletonLoader';
 22→import {LexicalRenderer} from '../../lib/content/LexicalRenderer';
 23→import {RelatedPosts} from '../../components/Discovery/RelatedPosts';
 24→import {useAuth} from '../../features/auth/AuthProvider';
 25→import {useTheme} from '../../theme/ThemeProvider';
 26→import {useComments} from '../../hooks/useComments';
 27→import {fonts, typeScale} from '../../theme/typography';
 28→import {spacing, radii} from '../../theme/spacing';
 29→import {mobileApi} from '../../lib/api/mobileApi';
 30→import {socialApi} from '../../lib/api/socialApi';
 31→import {queryClient} from '../../lib/queryClient';
 32→import type {RootStackParamList} from '../../navigation/types';
 33→
 34→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 35→
 36→const toCount = (value: unknown): number | null => {
 37→  const parsed = Number(value);
 38→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 39→};
 40→
 41→const resolveCount = (
 42→  aggregate: Array<{count?: number}> | undefined,
 43→  fallback?: number,
 44→): number => {
 45→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 46→};
 47→
 48→const extractBannerImage = (content: string | null | undefined): string | null => {
 49→  if (!content) return null;
 50→  try {
 51→    const parsed = JSON.parse(content);
 52→    const findImage = (node: any): string | null => {
 53→      if (node.type === 'image' && node.src) return node.src;
 54→      if (node.children) {
 55→        for (const child of node.children) {
 56→          const found = findImage(child);
 57→          if (found) return found;
 58→        }
 59→      }
 60→      return null;
 61→    };
 62→    return findImage(parsed.root ?? parsed);
 63→  } catch {
 64→    return null;
 65→  }
 66→};
 67→
 68→export function PostDetailScreen({route, navigation}: Props) {
 69→  const {user, session} = useAuth();
 70→  const {colors} = useTheme();
 71→  const {journalId} = route.params;
 72→  const token = session?.access_token ?? '';
 73→  const [repostCaption, setRepostCaption] = useState('');
 74→  const [showRepost, setShowRepost] = useState(false);
 75→  const scrollViewRef = useRef<ScrollView>(null);
 76→  const inputRef = useRef<TextInput>(null);
 77→
 78→  const onReplyActivated = useCallback(() => {
 79→    setTimeout(() => {
 80→      inputRef.current?.focus();
 81→      scrollViewRef.current?.scrollToEnd({animated: true});
 82→    }, 100);
 83→  }, []);
 84→
 85→  const detailQuery = useQuery({
 86→    queryKey: ['journal', journalId, user?.id],
 87→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 88→  });
 89→
 90→  const receiverId = (detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id) || undefined;
 91→
 92→  const {
 93→    comments,
 94→    isLoading: commentsLoading,
 95→    commentInput,
 96→    setCommentInput,
 97→    replyingTo,
 98→    setReplyingTo,
 99→    expandedReplies,
100→    fetchedReplies,
101→    loadingReplies,
102→    handleReply,
103→    handleToggleReplies,
104→    submitComment,
105→    isSubmitting,
106→  } = useComments(journalId, receiverId, token, onReplyActivated);
107→
108→  const reactionMutation = useMutation({
109→    mutationFn: async (reactionType: string) => {
110→      const journal = detailQuery.data?.journal;
111→      const rid = journal?.user_id ?? journal?.users?.id;
112→      if (!token) throw new Error('Please log in to react.');
113→      if (!journal?.id || !rid) throw new Error('Missing journal data.');
114→      return socialApi.toggleReaction(token, {
115→        journalId: journal.id,
116→        receiverId: rid,
117→        reactionType,
118→      });
119→    },
120→    onSuccess: () => {
121→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
122→      queryClient.invalidateQueries({queryKey: ['feed']});
123→    },
124→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
125→  });
126→
127→  const bookmarkMutation = useMutation({
128→    mutationFn: async () => {
129→      if (!token) throw new Error('Please log in to bookmark.');
130→      return socialApi.toggleBookmark(token, {journalId});
131→    },
132→    onSuccess: () => {
133→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
134→      queryClient.invalidateQueries({queryKey: ['feed']});
135→    },
136→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
137→  });
138→
139→  const repostMutation = useMutation({
140→    mutationFn: async () => {
141→      if (!token) throw new Error('Please log in to repost.');
142→      return socialApi.createRepost(token, {
143→        sourceJournalId: journalId,
144→        caption: repostCaption.trim() || undefined,
145→      });
146→    },
147→    onSuccess: () => {
148→      setRepostCaption('');
149→      setShowRepost(false);
150→      Alert.alert('Reposted', 'Post was reposted to your feed.');
151→      queryClient.invalidateQueries({queryKey: ['feed']});
152→    },
153→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
154→  });
155→
156→  const journal = detailQuery.data?.journal;
157→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
158→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
159→  const bookmarkCount = resolveCount(journal?.bookmark_count);
160→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
161→
162→  if (detailQuery.isLoading) {
163→    return (
164→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
165→        <View style={styles.loadingContainer}>
166→          <SkeletonLoader height={200} borderRadius={0} />
167→          <View style={styles.contentPadding}>
168→            <SkeletonLoader width="70%" height={24} />
169→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
170→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
171→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
172→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
173→          </View>
174→        </View>
175→      </SafeAreaView>
176→    );
177→  }
178→
179→  if (detailQuery.isError) {
180→    return (
181→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
182→        <View style={styles.contentPadding}>
183→          <Text style={[styles.errorText, {color: colors.danger}]}>
184→            Unable to load this post.
185→          </Text>
186→        </View>
187→      </SafeAreaView>
188→    );
189→  }
190→
191→  return (
192→    <ScrollView
193→      ref={scrollViewRef}
194→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
195→      showsVerticalScrollIndicator={false}>
196→      {/* Banner image */}
197→      {bannerImage && (
198→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
199→      )}
200→
201→      <View style={styles.contentPadding}>
202→        {/* Title */}
203→        <Text style={[styles.title, {color: colors.textHeading}]}>
204→          {journal?.title || 'Untitled Post'}
205→        </Text>
206→
207→        {/* Author section */}
208→        <Pressable
209→          style={styles.authorRow}
210→          onPress={() => {
211→            const authorId = journal?.users?.id ?? journal?.user_id;
212→            if (!authorId) return;
213→            if (authorId === user?.id) {
214→              navigation.navigate('Main' as any, {screen: 'Profile'});
215→            } else {
216→              navigation.navigate('VisitProfile', {
217→                userId: authorId,
218→                username: journal?.users?.username ?? undefined,
219→              });
220→            }
221→          }}>
222→          <Avatar
223→            uri={journal?.users?.image_url}
224→            name={journal?.users?.name}
225→            size={36}
226→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
227→          />
228→          <View style={styles.authorInfo}>
229→            <View style={styles.authorNameRow}>
230→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
231→                {journal?.users?.name || 'Unknown author'}
232→              </Text>
233→              {journal?.users?.badge ? (
234→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
235→              ) : null}
236→            </View>
237→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
238→              {formatRelativeDate(journal?.created_at)}
239→            </Text>
240→          </View>
241→        </Pressable>
242→
243→        {/* Action bar */}
244→        <ActionBar
245→          likeCount={likeCount}
246→          commentCount={commentCount}
247→          bookmarkCount={bookmarkCount}
248→          isLiked={journal?.has_liked}
249→          isBookmarked={journal?.has_bookmarked}
250→          userReaction={journal?.user_reaction}
251→          onReact={type => reactionMutation.mutate(type)}
252→          onComment={() => {/* scroll to comments */}}
253→          onBookmark={() => bookmarkMutation.mutate()}
254→          onRepost={() => setShowRepost(!showRepost)}
255→        />
256→
257→        {/* Repost section */}
258→        {showRepost && (
259→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
260→            <TextInput
261→              value={repostCaption}
262→              onChangeText={setRepostCaption}
263→              placeholder="Add an optional caption"
264→              placeholderTextColor={colors.textFaint}
265→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
266→              maxLength={280}
267→              multiline
268→            />
269→            <PrimaryButton
270→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
271→              onPress={() => repostMutation.mutate()}
272→              disabled={repostMutation.isPending}
273→            />
274→          </View>
275→        )}
276→
277→        {/* Divider */}
278→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
279→
280→        {/* Content body */}
281→        <LexicalRenderer content={journal?.content} />
282→
283→        {/* Related posts */}
284→        <RelatedPosts journalId={journalId} />
285→
286→        {/* Divider */}
287→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
288→
289→        {/* Comments section */}
290→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
291→          Comments ({commentCount})
292→        </Text>
293→
294→        {commentsLoading ? (
295→          <View style={styles.commentLoading}>
296→            <ActivityIndicator color={colors.loaderColor} />
297→          </View>
298→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
299→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
300→            No comments yet. Be the first!
301→          </Text>
302→        ) : (
303→          comments
304→            .filter(c => !c.parent_id)
305→            .map(comment => (
306→              <CommentThread
307→                key={comment.id}
308→                comment={comment}
309→                postId={journalId}
310→                allComments={comments}
311→                fetchedReplies={fetchedReplies}
312→                loadingReplies={loadingReplies}
313→                isLoggedIn={!!token}
314→                onReply={handleReply}
315→                onToggleReplies={handleToggleReplies}
316→                expandedReplies={expandedReplies}
317→                colors={colors}
318→                depth={0}
319→              />
320→            ))
321→        )}
322→
323→        {/* Comment input */}
324→        {token ? (
325→          <View style={styles.commentInputRow}>
326→            {replyingTo && (
327→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
328→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
329→                  Replying to {replyingTo.userName}
330→                </Text>
331→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
332→                  <XIcon size={16} color={colors.textMuted} />
333→                </Pressable>
334→              </View>
335→            )}
336→            <TextInput
337→              ref={inputRef}
338→              value={commentInput}
339→              onChangeText={setCommentInput}
340→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
341→              placeholderTextColor={colors.textFaint}
342→              style={[
343→                styles.commentInput,
344→                {
345→                  backgroundColor: colors.bgSecondary,
346→                  borderColor: colors.borderCard,
347→                  color: colors.textPrimary,
348→                },
349→              ]}
350→              maxLength={200}
351→              multiline
352→            />
353→            <PrimaryButton
354→              label={isSubmitting ? 'Posting...' : 'Post'}
355→              onPress={submitComment}
356→              disabled={commentInput.trim().length === 0 || isSubmitting}
357→            />
358→          </View>
359→        ) : null}
360→
361→        <View style={styles.bottomSpacer} />
362→      </View>
363→    </ScrollView>
364→  );
365→}
