108→const authHeaders = (token?: string): Record<string, string> => {
109→  if (!token) {
110→    return {};
111→  }
112→
113→  return {
114→    Authorization: `Bearer ${token}`,
115→  };
116→};
117→
118→export const mobileApi = {
119→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
120→    const params = new URLSearchParams();
121→    params.set('limit', String(limit));
122→    if (cursor) {
123→      params.set('before', cursor);
124→    }
125→    if (userId) {
126→      params.set('userId', userId);
127→    }
128→
129→    return apiRequest<CursorPage<JournalItem>>(`/journals?${params.toString()}`, {
130→      method: 'GET',
131→    });
132→  },
133→
134→  async getJournalById(journalId: string, userId?: string): Promise<{ journal: JournalItem }> {
135→    const params = new URLSearchParams();
136→    if (userId) {
137→      params.set('userId', userId);
138→    }
139→
140→    const suffix = params.toString() ? `?${params.toString()}` : '';
141→    return apiRequest<{ journal: JournalItem }>(`/journal/${encodeURIComponent(journalId)}${suffix}`, {
142→      method: 'GET',
143→    });
144→  },
145→
146→  async searchUsers(query: string, limit = 20): Promise<{ data: UserPreview[]; hasMore: boolean }> {
147→    const params = new URLSearchParams();
148→    params.set('query', query.trim());
149→    params.set('limit', String(limit));
150→
151→    return apiRequest<{ data: UserPreview[]; hasMore: boolean }>(`/users/search?${params.toString()}`, {
152→      method: 'GET',
153→    });
154→  },
155→
156→  async searchJournals(query: string, limit = 20, userId?: string): Promise<{ data: JournalItem[]; hasMore: boolean }> {
157→    const params = new URLSearchParams();
158→    params.set('query', query.trim());
159→    params.set('limit', String(limit));
160→    if (userId) {
161→      params.set('userId', userId);
162→    }
163→
164→    return apiRequest<{ data: JournalItem[]; hasMore: boolean }>(`/journals/search?${params.toString()}`, {
165→      method: 'GET',
166→    });
167→  },
168→
169→  async getNotifications(token: string, cursor: string | null, limit = 20): Promise<CursorPage<NotificationItem>> {
170→    const params = new URLSearchParams();
171→    params.set('limit', String(limit));
172→    if (cursor) {
173→      params.set('before', cursor);
174→    }
175→
176→    return apiRequest<CursorPage<NotificationItem>>(`/getNotifications?${params.toString()}`, {
177→      method: 'GET',
178→      headers: {
179→        ...authHeaders(token),
180→      },
181→    });
182→  },
183→
184→  async getStreak(userId: string): Promise<StreakResponse> {
185→    return apiRequest<StreakResponse>(`/streak/${encodeURIComponent(userId)}`, {
186→      method: 'GET',
187→    });
188→  },
189→
190→  async getUserData(userId: string): Promise<UserDataResponse> {
191→    const params = new URLSearchParams();
192→    params.set('userId', userId);
193→
194→    return apiRequest<UserDataResponse>(`/getUserData?${params.toString()}`, {
195→      method: 'GET',
196→    });
197→  },
198→
199→  async getCanvasGallery(
200→    userId?: string,
201→    limit = 36,
202→    sort: 'hottest' | 'newest' = 'hottest',
203→    cursor?: string | null,
204→  ): Promise<CursorPage<JournalItem>> {
205→    const params = new URLSearchParams();
206→    params.set('limit', String(limit));
207→    params.set('sort', sort);
208→    if (userId) {
