299→    const params = new URLSearchParams();
300→    params.set('limit', String(limit));
301→    params.set('userId', userId);
302→    if (cursor) params.set('before', cursor);
303→    return apiRequest<CursorPage<JournalItem>>(`/userJournals?${params.toString()}`, {
304→      method: 'GET',
305→      headers: {Authorization: `Bearer ${token}`},
306→    });
307→  },
308→
309→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
310→    const formData = new FormData();
311→
312→    const lexicalPayload = {
313→      root: {
314→        children: [
315→          {
316→            type: 'paragraph',
317→            children: [
318→              {
319→                type: 'text',
320→                text: payload.plainText,
321→                detail: 0,
322→                format: 0,
323→                mode: 'normal',
324→                style: '',
325→                version: 1,
326→              },
327→            ],
328→            direction: null,
329→            format: '',
330→            indent: 0,
331→            version: 1,
332→          },
333→        ],
334→        direction: null,
335→        format: '',
336→        indent: 0,
337→        type: 'root',
338→        version: 1,
339→      },
340→    };
341→
342→    formData.append('title', payload.title);
343→    formData.append('content', JSON.stringify(lexicalPayload));
344→    formData.append('post_type', 'text');
345→
346→    return apiRequest<{ message?: string }>('/save-journal', {
347→      method: 'POST',
348→      headers: {
349→        ...authHeaders(token),
350→      },
351→      body: formData,
352→      timeoutMs: 30000,
353→      retries: 0,
354→    });
355→  },
356→};
